parameters.jsCode:
// === slack-to-inbox: verify Slack signature + normalize into m2 schema-v1 capture ===
// Body of integrations/n8n/slack-normalize.js, inlined, plus Slack request-signature verification.
// Keep in lock-step with slack-normalize.js (its test guards it). See integrations/slack/README.md.
//
// Env (n8n Variables / container env):
//   SLACK_SIGNING_SECRET  — verify X-Slack-Signature
//   SLACK_BOT_TOKEN       — (optional here) used by lookup nodes for users.info/conversations.info
//   BRAIN_REPO (default your-org/brain), BRAIN_BRANCH (default main)
const crypto = require('crypto');
const item = $input.first().json;
const headers = item.headers || {};
const rawBody = (item.body && typeof item.body === 'string') ? item.body : ($json.rawBody || '');

// --- 1. verify Slack signature (HMAC v0) + reject replays (>5 min) ---
const secret = $env.SLACK_SIGNING_SECRET;
if (!secret) throw new Error('slack-to-inbox: SLACK_SIGNING_SECRET is not set');
const ts = headers['x-slack-request-timestamp'];
const sig = headers['x-slack-signature'];
if (!ts || !sig) throw new Error('slack-to-inbox: missing Slack signature headers');
if (Math.abs(Date.now()/1000 - Number(ts)) > 300) throw new Error('slack-to-inbox: stale request (replay?)');
const base = `v0:${ts}:${rawBody}`;
const mine = 'v0=' + crypto.createHmac('sha256', secret).update(base).digest('hex');
const ok = (mine.length === sig.length) && crypto.timingSafeEqual(Buffer.from(mine), Buffer.from(sig));
if (!ok) throw new Error('slack-to-inbox: bad Slack signature');

// --- 2. parse the Slack payload (view_submission shortcut, or reaction_added) ---
// Slack interactive payloads arrive urlencoded as payload=<json>; events arrive as JSON.
let payload;
if (rawBody.startsWith('payload=')) {
  payload = JSON.parse(decodeURIComponent(rawBody.slice('payload='.length)));
} else {
  payload = (typeof item.body === 'object') ? item.body : JSON.parse(rawBody);
}
// Slack URL verification handshake
if (payload.type === 'url_verification') { return [{ json: { _challenge: payload.challenge } }]; }

// Extract the common fields from either a modal submit or a reaction event.
let text = '', tsMsg = '', title = '', hint = '', channel = '', author = '';
if (payload.type === 'view_submission') {
  const md = payload.view.private_metadata ? JSON.parse(payload.view.private_metadata) : {};
  text = md.text || ''; tsMsg = md.ts || ''; channel = md.channel_name || ''; author = md.author || '';
  const vals = payload.view.state && payload.view.state.values ? payload.view.state.values : {};
  for (const blk of Object.values(vals)) for (const f of Object.values(blk)) {
    if (f.type === 'plain_text_input') title = (f.value || '').trim();
    if (f.type === 'static_select' && f.selected_option) hint = f.selected_option.value || '';
  }
} else if (payload.event && payload.event.type === 'reaction_added') {
  // The lookup nodes (not shown) should enrich text/author/channel from the reacted item via the bot token.
  text = payload.event._text || ''; tsMsg = (payload.event.item && payload.event.item.ts) || '';
  channel = payload.event._channel_name || ''; author = payload.event._author || '';
} else {
  throw new Error('slack-to-inbox: unsupported interaction type');
}

// --- 3. normalize (mirror of slack-normalize.js buildCapture) ---
const p2 = (n) => String(n).padStart(2, '0');
const canonicalISO = (iso) => { const d = new Date(iso); if (Number.isNaN(d.getTime())) throw new Error(`invalid 'captured': ${iso}`); return d.toISOString().replace(/\.\d{3}Z$/, 'Z'); };
const isoFromSlackTs = (t) => { const s = Number(String(t).split('.')[0]); if (!Number.isFinite(s) || s <= 0) throw new Error(`invalid Slack ts: ${t}`); return new Date(s*1000).toISOString().replace(/\.\d{3}Z$/, 'Z'); };
const stampFromISO = (iso) => { const d = new Date(iso); if (Number.isNaN(d.getTime())) throw new Error(`invalid 'captured': ${iso}`); return `${d.getUTCFullYear()}-${p2(d.getUTCMonth()+1)}-${p2(d.getUTCDate())}-${p2(d.getUTCHours())}${p2(d.getUTCMinutes())}`; };
const yamlStr = (s) => `"${String(s).replace(/\\/g,'\\\\').replace(/"/g,'\\"')}"`;
const yamlList = (items) => `[${items.map((it)=>{const s=String(it).trim(); return /^[A-Za-z0-9_\-.]+$/.test(s)?s:yamlStr(s);}).join(', ')}]`;
const DIMS = ['technical','business','product','design','user'];

if (typeof text !== 'string' || text.trim() === '') throw new Error("'text' is required");
const capturedISO = canonicalISO(isoFromSlackTs(tsMsg));
const stamp = stampFromISO(capturedISO);
title = (title || '').trim();
if (!title) { const fl = text.trim().split('\n')[0].replace(/\s+/g,' ').slice(0,80); title = fl ? `Slack note — ${fl}` : `Slack note (${stamp})`; }
const participants = author ? [String(author).trim()].filter(Boolean) : [];
if (hint.toLowerCase() === 'let it decide' || hint.toLowerCase() === 'auto') hint = '';

const fm = ['---','source:    slack',`captured:  ${capturedISO}`,`title:     ${yamlStr(title)}`];
if (participants.length) fm.push(`participants: ${yamlList(participants)}`);
if (channel) fm.push(`channel:   ${yamlStr(channel.startsWith('#')?channel:('#'+channel))}`);
if (hint) fm.push(`hint:      ${DIMS.includes(hint)?hint:yamlStr(hint)}`);
fm.push('---');
const content = `${fm.join('\n')}\n\n${text.replace(/\s+$/,'')}\n`;
const filename = `slack-${stamp}.md`;

return [{ json: {
  path: `_inbox/${filename}`,
  filename,
  capturedISO,
  contentB64: Buffer.from(content, 'utf8').toString('base64'),
  commitMessage: `feat(inbox): slack capture ${filename}`,
  brainRepo: $env.BRAIN_REPO || 'your-org/brain',
  branch: $env.BRAIN_BRANCH || 'main',
  responseUrl: (payload.response_url || (payload.view && JSON.parse(payload.view.private_metadata||'{}').response_url) || '')
} }];

